import{_ as t,o as i,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"3. Definitions","description":"","frontmatter":{"title":"3. Definitions","eba":"Medical Specialists 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/preliminary/3-definitions.md","filePath":"ebas/medical-specialists/preliminary/3-definitions.md"}'),r={name:"ebas/medical-specialists/preliminary/3-definitions.md"};function n(s,e,c,p,l,h){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_3-definitions" tabindex="-1">3. Definitions <a class="header-anchor" href="#_3-definitions" aria-label="Permalink to &quot;3. Definitions&quot;">​</a></h1><p><strong>3.1</strong> In this Agreement except where the context requires otherwise:</p><p><strong>(a)</strong> 2013 Specialists Agreement means the AMA Victoria – Victorian Public Health Sector - Medical Specialists Enterprise Agreement 2013.</p><p><strong>(b)</strong> 2018 Specialists Agreement means the AMA Victoria – Victorian Public Health Sector - Medical Specialists Enterprise Agreement 2018-2021.</p><p><strong>(c)</strong> Act unless otherwise specified means the Fair Work Act 2009 (Cth), as amended or replaced from time to time.</p><p><strong>(d)</strong> Agreement means the Medical Specialists (Victorian Public Health Sector) (AMA Victoria/ASMOF) (Single Interest Employers) Enterprise Agreement 2022 – 2026.</p><p><strong>(e)</strong> Ambassador means an appointed representative of the Association.</p><p><strong>(f)</strong> Association means the Australian Medical Association (Victoria) Limited (“AMA”) or the Australian Salaried Medical Officers Federation (Victoria Branch) (“ASMOF”).</p><p><strong>(g)</strong> ATO means the Australian Taxation Office.</p><p><strong>(h)</strong> Clinical Academic means a specialist registered by the Medical Board of Australia and who is employed in a Full Time capacity by a University in an academic role in the faculty of medicine (however described) and also employed by a Health Service.</p><p><strong>(i)</strong> CME means Continuing Medical Education.</p><p><strong>(j)</strong> CME Support Entitlement means the amount of funding support for CME that a Doctor is entitled to in a Financial Year, calculated in accordance with</p><p>subclause 41.1(a) (for a Full-time Doctor) or subclause 41.1(c) (for a Fractional Doctor).</p><p><strong>(k)</strong> Doctor–</p><p><strong>(i)</strong> means a medical practitioner employed by a Health Service as a Specialist or Executive Specialist as a Full-Time Doctor, Fractional Doctor or Internal Locum Doctor ; but</p><p><strong>(ii)</strong> with respect to Dental Health Services Victoria, means only a Doctor employed as an Anaesthetist.</p><p><strong>(l)</strong> Doctors in Training Agreement means the Doctors in Training (Victorian Public Health Sector) (AMA Victoria/ASMOF) (Single Interest Employers) Enterprise Agreement 2022 – 2026.</p><p><strong>(m)</strong> DH means the Department of Health, or it’s successor, however titled or styled.</p><p><strong>(n)</strong> EO Act means the Equal Opportunity Act 2010 (Vic), as amended or replaced from time to time.</p><p><strong>(o)</strong> Employee has the same meaning as Doctor</p><p><strong>(p)</strong> Employer has the same meaning as Health Service</p><p><strong>(q)</strong> Executive Specialist means a Doctor who is expressly appointed by his or her Health Service as an Executive Specialist and:</p><p><strong>(i)</strong> is required in his or her employment to exercise professional leadership and/or management accountability which is clearly outside of the responsibility of other Specialists; and either</p><p><strong>(ii)</strong> holds Specialist Registration with the Medical Practitioners Board of Australia under the Health Practitioner Regulation National Law Act 2009 (Vic); or</p><p><strong>(iii)</strong> possesses a higher qualification appropriate to the speciality in which they are employed or has sufficient experience in their speciality to satisfy the Health Service by which they are employed that the appointment is warranted.</p><p><strong>(iv)</strong> Examples of such responsibilities of Executive Specialists could include:</p><p>A. responsibility over a range of programs;</p><p>B. direct supervision of a number of Specialists who are department/unit heads;</p><p>C. required to serve on the Executive Management Team of the Health Service; or</p><p>D. demonstrated leadership in the activities of a national and/or international learned College or Society within their discipline.</p><p><strong>(r)</strong> Fractional Doctor means a Doctor engaged on a fractional basis in accordance with subclause 16.2.</p><p><strong>(s)</strong> Full-time Doctor means a Doctor engaged on a Full-Time basis in accordance with subclause 16.1(a).</p><p><strong>(t)</strong> FWC means the Fair Work Commission.</p><p><strong>(u)</strong> Health Service means a public hospital or health service listed in <a href="/eba/ebas/doctors-in-training/appendices/1-list-of-employers-health-services.html">Appendix 1</a>.</p><p><strong>(v)</strong> Health Services Act means the Health Services Act 1988 (Vic), as amended or replaced from time to time.</p><p><strong>(w)</strong> Higher Qualification means a qualification appropriate to the specialty in which a Doctor is employed conferred upon the Doctor by a University, Medical School or Learned College including:</p><p><strong>(i)</strong> postgraduate degrees and diplomas of Universities;</p><p><strong>(ii)</strong> membership or fellowship of a Specialist Medical College or Association of Specialists;</p><p><strong>(iii)</strong> any other postgraduate qualification at the level of Masters or above appropriate to the specialty in which the Doctor is employed;</p><p><strong>(iv)</strong> where the minimum compulsory training period in that specialty required to qualify for the postgraduate qualification exceeds four years, years in excess of four will be counted as experience after obtaining higher qualification in the definition of Senior Specialist, Principal Specialist and Senior Principal Specialist.</p><p><strong>(x)</strong> HSR means a health and safety representative (including a deputy health and safety representative) elected under the OHS Act.</p><p><strong>(y)</strong> Internal Locum means a Doctor engaged on a casual basis in accordance with subclause 16.4.</p><p><strong>(z)</strong> Institution means any hospital, health service (whether or not listed in <a href="/eba/ebas/doctors-in-training/appendices/1-list-of-employers-health-services.html">Appendix 1</a>) or benevolent home, community health centre, Society or Association registered pursuant to the Health Services Act.</p><p><strong>(aa)</strong> NES means the National Employment Standards.</p><p><strong>(bb)</strong> OHS Act means the Occupational Health and Safety Act 2004 (Vic), as amended or replaced from time to time.</p><p><strong>(cc)</strong> Portable Technological Aids means items which are easily portable and designed for use away from the Doctors’ usual work site; can operate without an external power supply; and are designed as a complete unit. For the purposes of this Agreement, items of a capital nature, such as ultrasound imaging devices, are not Portable Technological Aids.</p><p><strong>(dd)</strong> Private Practice Income means income derived by a Doctor because of the exercise of private practice privileges, whether or not the income is collected directly by the Doctor or passes through the hands of the Health Service acting as agent for the Doctor, and includes a private practice fund, a special purpose fund, a Dillon Fund or other private practice arrangement.</p><p><strong>(ee)</strong> Regulations means the Fair Work Regulations, as varied from time to time, and any successor to those Regulations</p><p><strong>(ff)</strong> Shiftworker, for the purposes of the NES, is any Doctor who is required to work in excess of their ordinary hours, or works ordinary hours on more than 10 weekends (defined as a Saturday or Sunday or both) during the leave accrual year.</p><p><strong>(gg)</strong> Specialist means a Doctor who:</p><p><strong>(i)</strong> holds Specialist Registration with the Medical Practitioners Board of Australia under the Health Practitioner Regulation National Law Act 2009 (Vic); or</p><p><strong>(ii)</strong> possesses a Higher Qualification appropriate to the speciality in which they are employed or has sufficient experience in their speciality to satisfy the Health Service that the appointment is warranted.</p><p><strong>(hh)</strong> Specialist Medical College means a medical college accredited by the Australian Medical Council.</p><p><strong>(ii)</strong> Specialty means a field of work requiring the application of special experience and qualifications in a particular branch of medicine.</p><p><strong>(jj)</strong> Statutory Body means the Department of Health (Victoria) and, formerly the Department of Health and Human Services (Victoria) and the Department of Human Services (Victoria).</p><p><strong>(kk)</strong> WIRC Act means the Workplace Injury Rehabilitation and Compensation Act 2013 (Vic), or if applicable in the particular situation the Accident Compensation Act 1985 (Vic) or the Workers Compensation Act 1958 (Vic).</p><p><strong>(ll)</strong> Except where the context requires otherwise, a reference in this Agreement to “Hospital”, &quot;hospital&quot; or &quot;health care facility&quot;, &quot;public health sector agency&quot;, “Health Service” or similar term is a reference to the hospital, health care facility, public health sector agency operated by a Health Service listed in</p><p><strong>(mm)</strong> Where an Act of Parliament or Regulation referred to in this Agreement is or has been replaced by another Act of Parliament or Regulation, the reference to such an Act or Regulation shall be taken to refer to the successor Act or Regulation.</p><p><strong>(nn)</strong> Where this Agreement refers to a condition of employment provided for in the NES, the relevant definitions in the Act apply.</p><p>Plain language terms: glossary, meanings.</p>',60)])])}const m=t(r,[["render",n]]);export{g as __pageData,m as default};
